     6→
     7→const __dirname = dirname(fileURLToPath(import.meta.url));
     8→const app = express();
     9→const PORT = 3000;
    10→
    11→app.use(express.json());
    12→app.use(express.static(join(__dirname, 'public')));
    13→
    14→// Inline the API handler (mirrors api/chat.js)
    15→app.post('/api/chat', async (req, res) => {
    16→  const handler = (await import('./api/chat.js')).default;
    17→  await handler(req, res);
    18→});
