     1→export default async function handler(req, res) {
     2→  if (req.method !== 'POST') {
     3→    return res.status(405).json({ error: 'Method not allowed' });
     4→  }
     5→
     6→  const { messages } = req.body;
     7→
     8→  if (!messages || !Array.isArray(messages)) {
     9→    return res.status(400).json({ error: 'Invalid request body' });
    10→  }
    11→
    12→  const apiKey = process.env.GROQ_API_KEY;
    13→  if (!apiKey) {
    14→    return res.status(500).json({ error: 'API key not configured' });
    15→  }
    16→
    17→  const systemPrompt = `You are CosmoBot, an enthusiastic and knowledgeable space exploration assistant. You have deep expertise in:
    18→
    19→- Space missions (past, present, and future) — NASA, ESA, SpaceX, ISRO, Roscosmos, etc.
    20→- Astronomy and astrophysics — black holes, neutron stars, galaxies, dark matter, dark energy
    21→- Planetary science — the solar system, exoplanets, moons, asteroids, comets
    22→- Rocket science and orbital mechanics — launch vehicles, trajectories, delta-v, Hohmann transfers
    23→- Space history — from Sputnik to the ISS, Apollo program, Space Shuttle era
    24→- Future exploration — Mars colonization, Artemis program, space telescopes, SETI
    25→- Cosmology — Big Bang, cosmic inflation, the fate of the universe
    26→
    27→Personality traits:
    28→- Passionate and awe-inspiring — convey the wonder of space
    29→- Accurate and educational — cite real missions, dates, and data
    30→- Approachable — explain complex concepts with analogies when needed
    31→- Concise but thorough — give satisfying answers without unnecessary padding
    32→
    33→Formatting:
    34→- Use **bold** for key terms, mission names, and important values
    35→- Use bullet lists when enumerating items (e.g., stages of a process, list of missions)
    36→- Use \`inline code\` for specific values, numbers, or formulas (e.g., \`delta-v = 3.2 km/s\`)
    37→- Avoid h1/h2 headers — use bold text for sub-topics instead
    38→- Keep responses under 300 words unless a detailed explanation is truly warranted
    39→
    40→If asked about non-space topics, gently redirect: "That's outside my cosmic expertise — ask me about the universe instead!"`;
    41→
    42→  try {
    43→    const response = await fetch('https://api.groq.com/openai/v1/chat/completions', {
    44→      method: 'POST',
    45→      headers: {
    46→        'Authorization': `Bearer ${apiKey}`,
    47→        'Content-Type': 'application/json',
    48→      },
    49→      body: JSON.stringify({
    50→        model: 'llama-3.3-70b-versatile',
    51→        messages: [
    52→          { role: 'system', content: systemPrompt },
    53→          ...messages.slice(-20),
    54→        ],
    55→        temperature: 0.72,
    56→        max_tokens: 1024,
    57→        stream: false,
    58→      }),
    59→    });
    60→
    61→    if (!response.ok) {
    62→      const err = await response.json().catch(() => ({}));
    63→      console.error('Groq API error:', err);
    64→      return res.status(response.status).json({ error: err.error?.message || 'Groq API error' });
    65→    }
    66→
    67→    const data = await response.json();
    68→    const content = data.choices?.[0]?.message?.content;
    69→
    70→    if (!content) {
    71→      return res.status(500).json({ error: 'Empty response from model' });
    72→    }
    73→
    74→    return res.status(200).json({ message: content });
    75→  } catch (err) {
    76→    console.error('Handler error:', err);
    77→    return res.status(500).json({ error: 'Internal server error' });
    78→  }
    79→}
    80→

