    44→/* ─── Starfield + Shooting Stars ─────────────────────────────────────────── */
    45→(function initStarfield() {
    46→  const canvas = document.getElementById('starfield');
    47→  const ctx = canvas.getContext('2d');
    48→  let stars = [];
    49→  const shootingStars = [];
    50→  let frame = 0;
    51→  let nextShoot = 240;
    52→
    53→  function resize() {
    54→    canvas.width  = window.innerWidth;
    55→    canvas.height = window.innerHeight;
    56→    buildStars();
    57→  }
    58→
    59→  function buildStars() {
    60→    const count = Math.floor((canvas.width * canvas.height) / 6000);
    61→    stars = Array.from({ length: Math.min(count, 220) }, () => ({
    62→      x:     Math.random() * canvas.width,
    63→      y:     Math.random() * canvas.height,
    64→      r:     Math.random() * 1.3 + 0.2,
    65→      alpha: Math.random(),
    66→      speed: Math.random() * 0.008 + 0.003,
    67→      dir:   Math.random() > 0.5 ? 1 : -1,
    68→    }));
    69→  }
    70→
    71→  function spawnShootingStar() {
    72→    shootingStars.push({
    73→      x:   Math.random() * canvas.width * 0.7,
    74→      y:   Math.random() * canvas.height * 0.45,
    75→      vx:  Math.random() * 7 + 5,
    76→      vy:  Math.random() * 3 + 1.5,
    77→      len: Math.random() * 110 + 60,
    78→      alpha: 1,
    79→    });
    80→  }
    81→
    82→  function draw() {
    83→    frame++;
    84→    ctx.clearRect(0, 0, canvas.width, canvas.height);
    85→
    86→    // Twinkling stars
    87→    for (const s of stars) {
    88→      s.alpha += s.speed * s.dir;
    89→      if (s.alpha >= 1 || s.alpha <= 0) s.dir *= -1;
    90→      ctx.beginPath();
    91→      ctx.arc(s.x, s.y, s.r, 0, Math.PI * 2);
    92→      ctx.fillStyle = `rgba(180, 210, 255, ${s.alpha.toFixed(3)})`;
    93→      ctx.fill();
    94→    }
    95→
    96→    // Shooting stars
    97→    if (frame >= nextShoot) {
    98→      spawnShootingStar();
    99→      nextShoot = frame + Math.floor(Math.random() * 300 + 180);
   100→    }
   101→
   102→    for (let i = shootingStars.length - 1; i >= 0; i--) {
   103→      const ss = shootingStars[i];
   104→      const mag = Math.hypot(ss.vx, ss.vy);
   105→      const tailX = ss.x - (ss.vx / mag) * ss.len;
   106→      const tailY = ss.y - (ss.vy / mag) * ss.len;
   107→
   108→      const grad = ctx.createLinearGradient(ss.x, ss.y, tailX, tailY);
   109→      grad.addColorStop(0, `rgba(210, 230, 255, ${ss.alpha})`);
   110→      grad.addColorStop(1, 'rgba(210, 230, 255, 0)');
   111→
   112→      ctx.beginPath();
   113→      ctx.moveTo(ss.x, ss.y);
   114→      ctx.lineTo(tailX, tailY);
   115→      ctx.strokeStyle = grad;
   116→      ctx.lineWidth = 1.5;
   117→      ctx.stroke();
   118→
   119→      ss.x += ss.vx;
   120→      ss.y += ss.vy;
   121→      ss.alpha -= 0.019;
   122→
   123→      if (ss.alpha <= 0 || ss.x > canvas.width + 100 || ss.y > canvas.height + 100) {
   124→        shootingStars.splice(i, 1);
   125→      }
   126→    }
   127→
   128→    requestAnimationFrame(draw);
   129→  }
   130→
   131→  window.addEventListener('resize', resize);
   132→  resize();
   133→  draw();
   134→})();
