   143→/* ─── State ──────────────────────────────────────────────────────────────── */
   144→const messages = [];
   145→let isLoading = false;
   146→
   147→/* ─── DOM refs ───────────────────────────────────────────────────────────── */
   148→const welcomeState  = document.getElementById('welcomeState');
   149→const messagesEl    = document.getElementById('messages');
