   219→/* ─── Core submit ────────────────────────────────────────────────────────── */
   220→async function submitMessage() {
   221→  const text = userInput.value.trim();
   222→  if (!text) return;
   223→
   224→  welcomeState.classList.add('hidden');
   225→  clearBtn.classList.remove('hidden');
   226→  userInput.value = '';
   227→  userInput.style.height = 'auto';
   228→  charCountEl.textContent = '0 / 1000';
   229→  charCountEl.classList.remove('warn', 'limit');
   230→
   231→  messages.push({ role: 'user', content: text });
   232→  appendBubble('user', text);
   233→
   234→  const typingEl = appendTyping();
   235→  setLoading(true);
   236→
   237→  try {
   238→    const res = await fetch('/api/chat', {
   239→      method: 'POST',
   240→      headers: { 'Content-Type': 'application/json' },
   241→      body: JSON.stringify({ messages }),
   242→    });
   243→
   244→    typingEl.remove();
   245→
   246→    if (!res.ok) {
   247→      const err = await res.json().catch(() => ({}));
   248→      appendError(err.error || `Error ${res.status} — please try again.`);
   249→      return;
   250→    }
   251→
   252→    const data = await res.json();
   253→    const reply = data.message;
   254→
   255→    messages.push({ role: 'assistant', content: reply });
   256→    appendBubble('bot', reply);
   257→
   258→  } catch (err) {
   259→    typingEl.remove();
   260→    appendError('Network error — check your connection and try again.');
   261→  } finally {
   262→    setLoading(false);
   263→  }
   264→}
