   276→
   277→const COPY_ICON = `<svg width="13" height="13" viewBox="0 0 24 24" fill="none"><rect x="9" y="9" width="13" height="13" rx="2" stroke="currentColor" stroke-width="2"/><path d="M5 15H4a2 2 0 01-2-2V4a2 2 0 012-2h9a2 2 0 012 2v1" stroke="currentColor" stroke-width="2"/></svg>`;
   278→const CHECK_ICON = `<svg width="13" height="13" viewBox="0 0 24 24" fill="none"><path d="M20 6L9 17l-5-5" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"/></svg>`;
   279→
   280→function appendBubble(role, text) {
   281→  const isUser = role === 'user';
   282→  const msg = document.createElement('div');
   283→  msg.className = `message ${role}`;
   284→  const time = formatTime(new Date());
   285→
   286→  if (isUser) {
   287→    msg.innerHTML = `
   288→      <div class="avatar">👤</div>
   289→      <div class="bubble-wrap">
   290→        <div class="bubble">${escapeHtml(text)}</div>
   291→        <span class="msg-time">${time}</span>
   292→      </div>
   293→    `;
   294→  } else {
   295→    msg.innerHTML = `
   296→      <div class="avatar">🚀</div>
   297→      <div class="bubble-wrap">
   298→        <div class="bubble prose">${renderMarkdown(text)}</div>
   299→        <div class="bubble-footer">
   300→          <span class="msg-time">${time}</span>
   301→          <button class="copy-btn" title="Copy response" aria-label="Copy response">
   302→            ${COPY_ICON} Copy
   303→          </button>
   304→        </div>
   305→      </div>
   306→    `;
   307→
   308→    msg.querySelector('.copy-btn').addEventListener('click', async () => {
   309→      const btn = msg.querySelector('.copy-btn');
   310→      try {
   311→        await navigator.clipboard.writeText(text);
   312→        btn.innerHTML = `${CHECK_ICON} Copied`;
   313→        btn.classList.add('copied');
   314→        setTimeout(() => {
   315→          btn.innerHTML = `${COPY_ICON} Copy`;
   316→          btn.classList.remove('copied');
   317→        }, 1800);
   318→      } catch {
   319→        // clipboard not available (e.g. non-HTTPS)
   320→      }
   321→    });
   322→  }
   323→
   324→  messagesEl.appendChild(msg);
   325→  scrollBottom();
   326→  return msg;
   327→}
   328→
   329→function appendTyping() {
   330→  const loadMsg = LOADING_MSGS[Math.floor(Math.random() * LOADING_MSGS.length)];
   331→  const msg = document.createElement('div');
   332→  msg.className = 'message bot';
   333→  msg.innerHTML = `
   334→    <div class="avatar">🚀</div>
   335→    <div class="bubble-wrap">
   336→      <div class="typing-bubble">
   337→        <span class="dot"></span>
   338→        <span class="dot"></span>
   339→        <span class="dot"></span>
   340→        <span class="typing-label">${loadMsg}</span>
   341→      </div>
   342→    </div>
   343→  `;
   344→  messagesEl.appendChild(msg);
   345→  scrollBottom();
   346→  return msg;
   347→}
   348→
   349→function appendError(text) {
   350→  const msg = document.createElement('div');
   351→  msg.className = 'message bot';
   352→  msg.innerHTML = `
   353→    <div class="avatar">🚀</div>
   354→    <div class="bubble-wrap">
   355→      <div class="error-bubble">
   356→        <span>⚠️</span>
   357→        <span>${escapeHtml(text)}</span>
   358→      </div>
   359→    </div>
   360→  `;
   361→  messagesEl.appendChild(msg);
   362→  scrollBottom();
   363→}
   364→
   365→function scrollBottom() {
   366→  chatContainer.scrollTo({ top: chatContainer.scrollHeight, behavior: 'smooth' });
   367→}
   368→
   369→function escapeHtml(str) {
   370→  return str
   371→    .replace(/&/g, '&amp;')
   372→    .replace(/</g, '&lt;')
   373→    .replace(/>/g, '&gt;')
   374→    .replace(/"/g, '&quot;')
   375→    .replace(/\n/g, '<br>');
   376→}
