    20→  --error-border:  rgba(220, 53, 69, 0.3);
    21→  --error-text:    #ff7b8a;
    22→  --radius-sm:     8px;
    23→  --radius-md:     14px;
    24→  --radius-lg:     20px;
    25→  --font-ui:       'Inter', system-ui, sans-serif;
    26→  --font-brand:    'Space Grotesk', system-ui, sans-serif;
    27→  --font-mono:     'SF Mono', 'Fira Code', 'Cascadia Code', monospace;
    28→  --header-h:      62px;
    29→  --max-w:         740px;
    30→}
    31→
    32→/* ─── Reset & Base ───────────────────────────────────────────────────────── */
    33→*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
    34→html { height: 100%; }
    35→
    36→body {
    37→  height: 100%;
    38→  font-family: var(--font-ui);
    39→  background: var(--bg-deep);
    40→  color: var(--text-primary);
    41→  overflow: hidden;
    42→}
    43→
    44→/* ─── Starfield Canvas ───────────────────────────────────────────────────── */
    45→#starfield {
    46→  position: fixed;
    47→  inset: 0;
    48→  z-index: 0;
    49→  pointer-events: none;
    50→}
    51→
    52→/* ─── Nebula Overlay ─────────────────────────────────────────────────────── */
    53→.nebula {
    54→  position: fixed;
    55→  inset: 0;
    56→  z-index: 0;
    57→  pointer-events: none;
    58→  background:
    59→    radial-gradient(ellipse 65% 55% at 15% 85%, rgba(88, 28, 135, 0.13) 0%, transparent 60%),
    60→    radial-gradient(ellipse 55% 45% at 85% 15%, rgba(14, 116, 144, 0.10) 0%, transparent 55%),
    61→    radial-gradient(ellipse 45% 65% at 55% 50%, rgba(30, 58, 138, 0.07) 0%, transparent 70%);
    62→}
    63→
    64→/* ─── App Shell ──────────────────────────────────────────────────────────── */
    65→.app {
    66→  position: relative;
    67→  z-index: 1;
    68→  display: flex;
    69→  flex-direction: column;
    70→  height: 100vh;
    71→  height: 100dvh;
    72→}
    73→
    74→/* ─── Header ─────────────────────────────────────────────────────────────── */
    75→.header {
    76→  height: var(--header-h);
    77→  border-bottom: 1px solid var(--border);
    78→  background: rgba(5, 10, 19, 0.85);
    79→  backdrop-filter: blur(12px);
    80→  -webkit-backdrop-filter: blur(12px);
    81→  flex-shrink: 0;
    82→}
    83→
    84→.header-inner {
    85→  max-width: var(--max-w);
    86→  margin: 0 auto;
    87→  height: 100%;
    88→  padding: 0 20px;
    89→  display: flex;
    90→  align-items: center;
    91→  justify-content: space-between;
    92→}
    93→
    94→.brand {
    95→  display: flex;
    96→  align-items: center;
    97→  gap: 10px;
    98→}
    99→
   100→.brand-icon {
   101→  font-size: 1.5rem;
   102→  animation: bob 3s ease-in-out infinite;
   103→  display: inline-block;
   104→}
