   387→/* ─── Markdown Prose ─────────────────────────────────────────────────────── */
   388→.bubble.prose p              { margin-bottom: 0.55em; }
   389→.bubble.prose p:last-child   { margin-bottom: 0; }
   390→.bubble.prose strong         { color: var(--accent-hover); font-weight: 600; }
   391→.bubble.prose em             { font-style: italic; color: var(--text-secondary); }
   392→.bubble.prose ul,
   393→.bubble.prose ol             { padding-left: 1.5em; margin: 0.4em 0; }
