   397→  font-family: var(--font-mono);
   398→  font-size: 0.83em;
   399→  background: rgba(91, 156, 246, 0.1);
   400→  border: 1px solid rgba(91, 156, 246, 0.18);
   401→  border-radius: 4px;
   402→  padding: 1px 5px;
   403→  color: var(--accent-hover);
   404→}
   405→.bubble.prose pre            {
