   520→
   521→/* ─── Input Area ─────────────────────────────────────────────────────────── */
   522→.input-area {
   523→  flex-shrink: 0;
   524→  background: rgba(5, 10, 19, 0.9);
   525→  backdrop-filter: blur(14px);
   526→  -webkit-backdrop-filter: blur(14px);
