   534→}
   535→
   536→.input-wrap {
   537→  display: flex;
   538→  align-items: flex-end;
   539→  gap: 10px;
   540→  background: var(--bg-input);
   541→  border: 1px solid var(--border);
   542→  border-radius: var(--radius-lg);
   543→  padding: 10px 10px 10px 16px;
   544→  transition: border-color 0.2s, box-shadow 0.2s;
