   565→
   566→.input-field::placeholder { color: var(--text-muted); }
   567→
   568→.input-field::-webkit-scrollbar { width: 4px; }
   569→.input-field::-webkit-scrollbar-thumb { background: var(--border); border-radius: 99px; }
   570→
   571→.send-btn {
   572→  width: 38px;
   573→  height: 38px;
   574→  border-radius: 50%;
   575→  border: none;
   576→  background: var(--accent);
   577→  color: white;
   578→  cursor: pointer;
   579→  display: flex;
   580→  align-items: center;
   581→  justify-content: center;
   582→  flex-shrink: 0;
   583→  transition: background 0.18s, transform 0.12s, opacity 0.18s;
