   597→}
   598→
   599→.disclaimer {
   600→  font-size: 0.72rem;
   601→  color: var(--text-muted);
   602→}
   603→
   604→.char-count {
   605→  font-size: 0.70rem;
   606→  color: var(--text-muted);
   607→  flex-shrink: 0;
   608→  font-variant-numeric: tabular-nums;
   609→  transition: color 0.2s;
   610→}
   611→
   612→.char-count.warn { color: #f59e0b; }
