   614→
   615→/* ─── Hidden utility ─────────────────────────────────────────────────────── */
   616→.hidden { display: none !important; }
   617→
   618→/* ─── Responsive ─────────────────────────────────────────────────────────── */
   619→@media (max-width: 600px) {
   620→  .brand-tagline { display: none; }
   621→  .welcome-title { font-size: 1.5rem; }
   622→  .welcome-sub   { font-size: 0.88rem; }
   623→  .bubble-wrap   { max-width: 90%; }
   624→  .suggestions   { gap: 8px; }
   625→  .chip          { font-size: 0.78rem; padding: 6px 12px; }
   626→  .scroll-fab    { bottom: 120px; right: 16px; }
   627→  .space-fact    { font-size: 0.78rem; }
   628→}
