/* ─── Design Tokens ─────────────────────────────────────────────────────── */
:root {
  --bg-deep:       #050a13;
  --bg-card:       #0d1626;
  --bg-input:      #111d30;
  --bg-user:       #1a3a6e;
  --bg-bot:        #0d1e35;
  --border:        rgba(99, 160, 255, 0.12);
  --border-focus:  rgba(99, 160, 255, 0.45);
  --text-primary:  #e8f0ff;
  --text-secondary:#8baad4;
  --text-muted:    #4a6280;
  --accent:        #5b9cf6;
  --accent-hover:  #7ab3ff;
  --accent-glow:   rgba(91, 156, 246, 0.25);
  --chip-bg:       rgba(91, 156, 246, 0.08);
  --chip-border:   rgba(91, 156, 246, 0.22);
  --chip-hover:    rgba(91, 156, 246, 0.18);
  --error-bg:      rgba(220, 53, 69, 0.12);
  --error-border:  rgba(220, 53, 69, 0.3);
  --error-text:    #ff7b8a;
  --radius-sm:     8px;
  --radius-md:     14px;
  --radius-lg:     20px;
  --font-ui:       'Inter', system-ui, sans-serif;
  --font-brand:    'Space Grotesk', system-ui, sans-serif;
  --font-mono:     'SF Mono', 'Fira Code', 'Cascadia Code', monospace;
  --header-h:      62px;
  --max-w:         740px;
}

/* ─── Reset & Base ───────────────────────────────────────────────────────── */
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
html { height: 100%; }

body {
  height: 100%;
  font-family: var(--font-ui);
  background: var(--bg-deep);
  color: var(--text-primary);
  overflow: hidden;
}

/* ─── Starfield Canvas ───────────────────────────────────────────────────── */
#starfield {
  position: fixed;
  inset: 0;
  z-index: 0;
  pointer-events: none;
}

/* ─── Nebula Overlay ─────────────────────────────────────────────────────── */
.nebula {
  position: fixed;
  inset: 0;
  z-index: 0;
  pointer-events: none;
  background:
    radial-gradient(ellipse 65% 55% at 15% 85%, rgba(88, 28, 135, 0.13) 0%, transparent 60%),
    radial-gradient(ellipse 55% 45% at 85% 15%, rgba(14, 116, 144, 0.10) 0%, transparent 55%),
    radial-gradient(ellipse 45% 65% at 55% 50%, rgba(30, 58, 138, 0.07) 0%, transparent 70%);
}

/* ─── App Shell ──────────────────────────────────────────────────────────── */
.app {
  position: relative;
  z-index: 1;
  display: flex;
  flex-direction: column;
  height: 100vh;
  height: 100dvh;
}

/* ─── Header ─────────────────────────────────────────────────────────────── */
.header {
  height: var(--header-h);
  border-bottom: 1px solid var(--border);
  background: rgba(5, 10, 19, 0.85);
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
  flex-shrink: 0;
}

.header-inner {
  max-width: var(--max-w);
  margin: 0 auto;
  height: 100%;
  padding: 0 20px;
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.brand {
  display: flex;
  align-items: center;
  gap: 10px;
}

.brand-icon {
  font-size: 1.5rem;
  animation: bob 3s ease-in-out infinite;
  display: inline-block;
}

@keyframes bob {
  0%, 100% { transform: translateY(0); }
  50%       { transform: translateY(-4px); }
}

.brand-name {
  font-family: var(--font-brand);
  font-size: 1.2rem;
  font-weight: 700;
  color: var(--text-primary);
  letter-spacing: -0.3px;
}

.header-right {
  display: flex;
  align-items: center;
  gap: 12px;
}

.brand-tagline {
  font-size: 0.75rem;
  color: var(--text-muted);
  font-weight: 500;
  letter-spacing: 0.5px;
  text-transform: uppercase;
}

/* ─── Icon Button (clear / reset) ───────────────────────────────────────── */
.icon-btn {
  width: 34px;
  height: 34px;
  border-radius: 50%;
  border: 1px solid var(--border);
  background: rgba(91, 156, 246, 0.06);
  color: var(--text-muted);
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: background 0.18s, border-color 0.18s, color 0.18s, transform 0.12s;
  flex-shrink: 0;
}

.icon-btn:hover {
  background: rgba(91, 156, 246, 0.14);
  border-color: var(--border-focus);
  color: var(--accent);
  transform: scale(1.08);
}

.icon-btn:active { transform: scale(0.96); }

/* ─── Chat Container ─────────────────────────────────────────────────────── */
.chat-container {
  flex: 1;
  overflow-y: auto;
  scroll-behavior: smooth;
  padding: 24px 20px;
  max-width: var(--max-w);
  width: 100%;
  margin: 0 auto;
}

.chat-container::-webkit-scrollbar { width: 5px; }
.chat-container::-webkit-scrollbar-track { background: transparent; }
.chat-container::-webkit-scrollbar-thumb { background: var(--border); border-radius: 99px; }

/* ─── Welcome State ──────────────────────────────────────────────────────── */
.welcome-state {
  display: flex;
  flex-direction: column;
  align-items: center;
  text-align: center;
  padding: 40px 0 24px;
  gap: 16px;
}

.welcome-graphic {
  position: relative;
  width: 80px;
  height: 80px;
  display: flex;
  align-items: center;
  justify-content: center;
}

.planet-emoji {
  font-size: 3.8rem;
  animation: spin-slow 20s linear infinite;
  display: inline-block;
}

@keyframes spin-slow {
  from { transform: rotate(0deg); }
  to   { transform: rotate(360deg); }
}

.star-emoji {
  position: absolute;
  color: var(--accent);
  font-size: 0.6rem;
  animation: twinkle 2.5s ease-in-out infinite;
}
.s1 { top: 4px;  right: 2px;  animation-delay: 0s; }
.s2 { bottom: 8px; left: 0px; animation-delay: 0.8s; }
.s3 { top: 50%;  left: -6px;  animation-delay: 1.6s; }

@keyframes twinkle {
  0%, 100% { opacity: 0.3; transform: scale(0.8); }
  50%       { opacity: 1;   transform: scale(1.4); }
}

.welcome-title {
  font-family: var(--font-brand);
  font-size: 1.9rem;
  font-weight: 700;
  color: var(--text-primary);
  letter-spacing: -0.5px;
}

.welcome-sub {
  font-size: 0.95rem;
  color: var(--text-secondary);
  max-width: 420px;
  line-height: 1.6;
}

/* ─── Space Fact ─────────────────────────────────────────────────────────── */
.space-fact {
  font-size: 0.82rem;
  color: var(--text-secondary);
  background: rgba(91, 156, 246, 0.07);
  border: 1px solid rgba(91, 156, 246, 0.16);
  border-radius: var(--radius-md);
  padding: 9px 16px;
  max-width: 440px;
  line-height: 1.5;
  animation: fade-in 0.6s ease-out;
}

@keyframes fade-in {
  from { opacity: 0; transform: translateY(4px); }
  to   { opacity: 1; transform: translateY(0); }
}

/* ─── Suggestion Chips ───────────────────────────────────────────────────── */
.suggestions {
  display: flex;
  flex-wrap: wrap;
  gap: 10px;
  justify-content: center;
  max-width: 560px;
  margin-top: 4px;
}

.chip {
  font-family: var(--font-ui);
  font-size: 0.82rem;
  font-weight: 500;
  color: var(--accent);
  background: var(--chip-bg);
  border: 1px solid var(--chip-border);
  border-radius: 99px;
  padding: 7px 15px;
  cursor: pointer;
  transition: background 0.18s, border-color 0.18s, color 0.18s, transform 0.12s;
  white-space: nowrap;
}

.chip:hover {
  background: var(--chip-hover);
  border-color: var(--accent);
  color: var(--accent-hover);
  transform: translateY(-1px);
}

.chip:active { transform: translateY(0); }

/* ─── Messages ───────────────────────────────────────────────────────────── */
.messages {
  display: flex;
  flex-direction: column;
  gap: 18px;
}

.message {
  display: flex;
  gap: 12px;
  animation: slide-in 0.22s ease-out;
}

@keyframes slide-in {
  from { opacity: 0; transform: translateY(8px); }
  to   { opacity: 1; transform: translateY(0); }
}

.message.user { flex-direction: row-reverse; }

.avatar {
  width: 34px;
  height: 34px;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 1rem;
  flex-shrink: 0;
  margin-top: 2px;
}

.message.user .avatar { background: var(--bg-user); border: 1px solid rgba(99,160,255,0.3); }
.message.bot  .avatar { background: var(--bg-card); border: 1px solid var(--border); }

/* ─── Bubble Wrap ────────────────────────────────────────────────────────── */
.bubble-wrap {
  display: flex;
  flex-direction: column;
  max-width: 82%;
  gap: 5px;
}

.message.user .bubble-wrap { align-items: flex-end; }

.bubble {
  padding: 13px 17px;
  border-radius: var(--radius-md);
  font-size: 0.92rem;
  line-height: 1.65;
  word-break: break-word;
}

.message.user .bubble {
  background: var(--bg-user);
  border: 1px solid rgba(99,160,255,0.22);
  border-bottom-right-radius: var(--radius-sm);
  color: var(--text-primary);
}

.message.bot .bubble {
  background: var(--bg-bot);
  border: 1px solid var(--border);
  border-bottom-left-radius: var(--radius-sm);
  color: var(--text-primary);
}

/* ─── Bubble Footer (timestamp + copy) ───────────────────────────────────── */
.bubble-footer {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 0 3px;
  gap: 12px;
}

.msg-time {
  font-size: 0.67rem;
  color: var(--text-muted);
  flex-shrink: 0;
}

.copy-btn {
  background: none;
  border: none;
  cursor: pointer;
  color: var(--text-muted);
  padding: 3px 5px;
  border-radius: 5px;
  display: flex;
  align-items: center;
  gap: 4px;
  font-size: 0.68rem;
  transition: color 0.15s, background 0.15s;
}

.copy-btn:hover {
  color: var(--accent);
  background: rgba(91, 156, 246, 0.1);
}

.copy-btn.copied { color: #4ade80; }

/* ─── Markdown Prose ─────────────────────────────────────────────────────── */
.bubble.prose p              { margin-bottom: 0.55em; }
.bubble.prose p:last-child   { margin-bottom: 0; }
.bubble.prose strong         { color: var(--accent-hover); font-weight: 600; }
.bubble.prose em             { font-style: italic; color: var(--text-secondary); }
.bubble.prose ul,
.bubble.prose ol             { padding-left: 1.5em; margin: 0.4em 0; }
.bubble.prose li             { margin-bottom: 0.25em; }
.bubble.prose li::marker     { color: var(--accent); }
.bubble.prose code           {
  font-family: var(--font-mono);
  font-size: 0.83em;
  background: rgba(91, 156, 246, 0.1);
  border: 1px solid rgba(91, 156, 246, 0.18);
  border-radius: 4px;
  padding: 1px 5px;
  color: var(--accent-hover);
}
.bubble.prose pre            {
  background: rgba(0, 0, 0, 0.45);
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  padding: 12px 14px;
  overflow-x: auto;
  margin: 0.6em 0;
}
.bubble.prose pre code       {
  background: none;
  border: none;
  padding: 0;
  font-size: 0.82em;
  color: var(--text-primary);
}
.bubble.prose h1,
.bubble.prose h2,
.bubble.prose h3             {
  font-family: var(--font-brand);
  font-weight: 700;
  margin: 0.6em 0 0.3em;
  color: var(--text-primary);
}
.bubble.prose h1             { font-size: 1.1em; }
.bubble.prose h2             { font-size: 1.0em; }
.bubble.prose h3             { font-size: 0.95em; }
.bubble.prose blockquote     {
  border-left: 3px solid var(--accent);
  padding-left: 12px;
  margin: 0.5em 0;
  color: var(--text-secondary);
  font-style: italic;
}
.bubble.prose a              { color: var(--accent); text-decoration: underline; }

/* ─── Typing Indicator ───────────────────────────────────────────────────── */
.typing-bubble {
  background: var(--bg-bot);
  border: 1px solid var(--border);
  border-radius: var(--radius-md);
  border-bottom-left-radius: var(--radius-sm);
  padding: 14px 18px;
  display: flex;
  gap: 5px;
  align-items: center;
}

.dot {
  width: 7px;
  height: 7px;
  background: var(--text-muted);
  border-radius: 50%;
  animation: bounce-dot 1.3s ease-in-out infinite;
}
.dot:nth-child(2) { animation-delay: 0.2s; }
.dot:nth-child(3) { animation-delay: 0.4s; }

@keyframes bounce-dot {
  0%, 60%, 100% { transform: translateY(0);    opacity: 0.4; }
  30%            { transform: translateY(-6px); opacity: 1;   }
}

.typing-label {
  font-size: 0.78rem;
  color: var(--text-muted);
  margin-left: 8px;
  font-style: italic;
}

/* ─── Error Bubble ───────────────────────────────────────────────────────── */
.error-bubble {
  background: var(--error-bg);
  border: 1px solid var(--error-border);
  border-radius: var(--radius-md);
  border-bottom-left-radius: var(--radius-sm);
  padding: 12px 16px;
  color: var(--error-text);
  font-size: 0.88rem;
  display: flex;
  align-items: center;
  gap: 8px;
}

/* ─── Scroll FAB ─────────────────────────────────────────────────────────── */
.scroll-fab {
  position: fixed;
  bottom: 130px;
  right: 24px;
  width: 38px;
  height: 38px;
  border-radius: 50%;
  border: 1px solid var(--border);
  background: rgba(13, 22, 38, 0.92);
  backdrop-filter: blur(10px);
  -webkit-backdrop-filter: blur(10px);
  color: var(--accent);
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 10;
  transition: opacity 0.2s, transform 0.2s, background 0.18s;
  box-shadow: 0 4px 16px rgba(0, 0, 0, 0.4);
}

.scroll-fab:hover {
  background: rgba(91, 156, 246, 0.15);
  transform: translateY(-2px);
}

.scroll-fab.hidden {
  opacity: 0;
  pointer-events: none;
  transform: translateY(8px);
}

/* ─── Input Area ─────────────────────────────────────────────────────────── */
.input-area {
  flex-shrink: 0;
  background: rgba(5, 10, 19, 0.9);
  backdrop-filter: blur(14px);
  -webkit-backdrop-filter: blur(14px);
  border-top: 1px solid var(--border);
  padding: 14px 20px 16px;
}

.input-form {
  max-width: var(--max-w);
  margin: 0 auto;
}

.input-wrap {
  display: flex;
  align-items: flex-end;
  gap: 10px;
  background: var(--bg-input);
  border: 1px solid var(--border);
  border-radius: var(--radius-lg);
  padding: 10px 10px 10px 16px;
  transition: border-color 0.2s, box-shadow 0.2s;
}

.input-wrap:focus-within {
  border-color: var(--border-focus);
  box-shadow: 0 0 0 3px var(--accent-glow);
}

.input-field {
  flex: 1;
  background: transparent;
  border: none;
  outline: none;
  color: var(--text-primary);
  font-family: var(--font-ui);
  font-size: 0.93rem;
  line-height: 1.5;
  resize: none;
  max-height: 140px;
  overflow-y: auto;
}

.input-field::placeholder { color: var(--text-muted); }

.input-field::-webkit-scrollbar { width: 4px; }
.input-field::-webkit-scrollbar-thumb { background: var(--border); border-radius: 99px; }

.send-btn {
  width: 38px;
  height: 38px;
  border-radius: 50%;
  border: none;
  background: var(--accent);
  color: white;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
  transition: background 0.18s, transform 0.12s, opacity 0.18s;
}

.send-btn:hover  { background: var(--accent-hover); transform: scale(1.06); }
.send-btn:active { transform: scale(0.96); }
.send-btn:disabled { opacity: 0.4; cursor: not-allowed; transform: none; }

/* ─── Input Meta Row ─────────────────────────────────────────────────────── */
.input-meta {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-top: 7px;
  padding: 0 2px;
}

.disclaimer {
  font-size: 0.72rem;
  color: var(--text-muted);
}

.char-count {
  font-size: 0.70rem;
  color: var(--text-muted);
  flex-shrink: 0;
  font-variant-numeric: tabular-nums;
  transition: color 0.2s;
}

.char-count.warn { color: #f59e0b; }
.char-count.limit { color: var(--error-text); }

/* ─── Hidden utility ─────────────────────────────────────────────────────── */
.hidden { display: none !important; }

/* ─── Responsive ─────────────────────────────────────────────────────────── */
@media (max-width: 600px) {
  .brand-tagline { display: none; }
  .welcome-title { font-size: 1.5rem; }
  .welcome-sub   { font-size: 0.88rem; }
  .bubble-wrap   { max-width: 90%; }
  .suggestions   { gap: 8px; }
  .chip          { font-size: 0.78rem; padding: 6px 12px; }
  .scroll-fab    { bottom: 120px; right: 16px; }
  .space-fact    { font-size: 0.78rem; }
}

